document.addEventListener('DOMContentLoaded', function () {
    // Alle kopieer-links in de portals-weergave
    // (genamespaced: .copy-btn botste met CSS/JS uit het template)
    document.querySelectorAll('.bragis-copy-link').forEach(function (btn) {
        btn.addEventListener('click', function (e) {
            // Het is een <a href="#">, dus de standaard-sprong onderdrukken
            e.preventDefault();

            var text = btn.getAttribute('data-copy') || '';

            // Visuele feedback: tekst kort naar "Gekopieerd", daarna terug naar "Kopieer"
            var done = function () {
                var original = btn.getAttribute('data-label') || 'Kopieer';
                var copied   = btn.getAttribute('data-label-copied') || 'Gekopieerd';

                // Lopende timer resetten bij snel opnieuw klikken
                if (btn._copyTimer) {
                    clearTimeout(btn._copyTimer);
                }

                btn.textContent = copied;
                btn.classList.add('is-copied');

                btn._copyTimer = setTimeout(function () {
                    btn.textContent = original;
                    btn.classList.remove('is-copied');
                    btn._copyTimer = null;
                }, 2000);
            };

            // Moderne clipboard-API, met fallback voor oudere browsers
            if (navigator.clipboard && navigator.clipboard.writeText) {
                navigator.clipboard.writeText(text).then(done).catch(function () {
                    fallbackCopy(text, done);
                });
            } else {
                fallbackCopy(text, done);
            }
        });
    });

    // Fallback: tijdelijk textarea selecteren en kopiëren
    function fallbackCopy(text, cb) {
        var ta = document.createElement('textarea');
        ta.value = text;
        ta.style.position = 'fixed';
        ta.style.opacity = '0';
        document.body.appendChild(ta);
        ta.select();
        try { document.execCommand('copy'); } catch (e) {}
        document.body.removeChild(ta);
        cb();
    }
});

document.addEventListener('DOMContentLoaded', function () {
    var input = document.getElementById('bragis-search-input');
    var grid  = document.querySelector('.bragis-grid');
    if (!input || !grid) {
        return;
    }
    // Alleen echte portal-kaarten filteren, niet de "toevoegen"-tegel
    var cards = grid.querySelectorAll('.card[data-search]');
    var noResults = document.getElementById('bragis-noresults');
    // De "Portal toevoegen"-tegel blijft altijd zichtbaar
    var addTile = grid.querySelector('.card-add');
    function applyFilter() {
        var term = input.value.trim().toLowerCase();
        var visibleCount = 0;
        cards.forEach(function (card) {
            var haystack = card.getAttribute('data-search') || '';
            // Lege zoekterm: alles tonen
            var match = (term === '' || haystack.indexOf(term) !== -1);
            card.style.display = match ? '' : 'none';
            if (match) {
                visibleCount++;
            }
        });
        // Toevoegen-tegel alleen tonen wanneer er niet gezocht wordt
        if (addTile) {
            addTile.style.display = (term === '') ? '' : 'none';
        }
        // "Geen resultaten"-melding tonen wanneer niets matcht en er wel gezocht wordt
        if (noResults) {
            noResults.hidden = !(visibleCount === 0 && term !== '');
        }
    }
    input.addEventListener('input', applyFilter);
});

