:root{
  --red:#ff0000; --red-dark:#cc0000; --red-glow:rgba(255,0,0,.08);
  --surface:#f5f5f5; --border:#e0e0e0; --text:#111; --muted:#666;
}
.bragis-grid{ display:grid; grid-template-columns:repeat(auto-fill,minmax(280px,1fr)); gap:20px; }
.card{
  background:var(--surface); border:1px solid var(--border); border-radius:8px;
  overflow:hidden; cursor:pointer; transition:border-color .2s, box-shadow .2s;
}
.card:hover{ border-color:var(--red); box-shadow:0 0 20px var(--red-glow); }
.card-image{
  height:120px; background:linear-gradient(135deg,#ececec,#e0e0e0);
  display:flex; align-items:center; justify-content:center; position:relative; overflow:hidden;
}
.card-image::after{ content:''; position:absolute; bottom:0; left:0; right:0; height:3px; background:var(--red); }
.card-image img.portal-img{ max-width:90%; max-height:90px; object-fit:contain; position:relative; z-index:1; }
.card-image .img-placeholder{ font-size:13px; color:#aaa; }
.card-meta{ padding:14px 16px 16px; }
.card-title{
  font-family:'Barlow Condensed',sans-serif; font-size:17px; font-weight:700;
  letter-spacing:.06em; text-transform:uppercase; color:var(--text);
}
.card-links{ display:flex; flex-wrap:wrap; gap:6px; }
.card-links a,
.card-links .card-link-info{
  display:inline-block; padding:5px 12px; border-radius:4px; font-size:12px; font-weight:500;
  letter-spacing:.04em; text-decoration:none; border:1px solid var(--border);
  color:var(--muted); transition:background .15s,color .15s,border-color .15s;
}
.card-links a:hover,
.card-links .card-link-info:hover{ background:var(--red); color:#fff; border-color:var(--red); }
/* Info-knop gedraagt zich als een link-knop: reset de button-defaults */
.card-links .card-link-info{
  background:none;              /* button heeft standaard een grijze achtergrond */
  font-family:inherit;         /* button erft het lettertype niet vanzelf */
  line-height:normal;
  cursor:pointer;
}
/* Extra informatie — zichtbaar voor iedereen */
.extra-info{
  margin-top:16px; font-size:14px; line-height:1.5; color:var(--text);
  border-top:1px solid var(--border);   /* scheidingslijn boven extra info */
  padding-top:12px;
}
.cred-list{ margin-top:16px; border-top:1px solid var(--border); padding-top:12px; }
/* min-width:0 op elk niveau: anders claimt de tekst zijn volle breedte
   en wordt de kopieer-link buiten de modal geduwd */
.cred-row{ display:flex; gap:10px; font-size:13px; padding:4px 0; min-width:0; }
.cred-label{ flex:0 0 130px; color:var(--muted); font-weight:600; }
.cred-value{ flex:1 1 0; min-width:0; word-break:break-all; }
.modal-edit{ margin-top:14px; text-align:right; }
.modal-edit .edit-link{ font-size:12px; color:var(--muted); text-decoration:none; }
.modal-edit .edit-link:hover{ color:var(--red); }
/* "Portal toevoegen"-tegel */
.card-add{
  border:1px dashed #ccc; border-radius:8px; display:flex; flex-direction:column;
  align-items:center; justify-content:center; gap:8px; min-height:180px; cursor:pointer;
  text-decoration:none; color:#aaa; transition:border-color .2s, background .2s;
}
.card-add:hover{ border-color:var(--red); background:var(--red-glow); }
.card-add span{ font-size:28px; color:#bbb; line-height:1; }
.card-add p{ font-size:13px; font-weight:500; letter-spacing:.04em; text-transform:uppercase; }
/* Waarde + kopieer-link naast elkaar.
   GEEN width:100% hier: die 100% rekent over de hele rij (dus incl. het 130px
   label), waardoor de span te breed werd en de link eruit duwde.
   flex:1 1 0 op .cred-value vult de resterende ruimte al precies. */
.cred-value-copy {
  display: flex;
  align-items: baseline;     /* waarde en link op dezelfde tekstlijn */
  gap: 0.75rem;
  min-width: 0;
}
/* flex-basis 0: de waarde mag NIET zijn content-breedte claimen,
   anders duwt hij de kopieer-link uit de modal */
.cred-value-copy .bragis-copy-text {
  flex: 1 1 0;
  min-width: 0;
  overflow-wrap: anywhere;   /* breekt ook lange strings zonder spaties */
  word-break: break-word;
}
/* Kopieer-link: tekstlink i.p.v. knop, zodat de rijhoogte gelijk blijft aan de tekst.
   Bewust genamespaced (.bragis-copy-link): generieke namen als .copy-btn
   botsen met CSS uit het template. */
.bragis-copy-link {
  flex: 0 0 auto;            /* nooit krimpen */
  font-size: 12px;
  font-weight: 500;
  letter-spacing: .04em;
/* text-transform: uppercase; */
  text-decoration: none;
  color: var(--muted);
  cursor: pointer;
  white-space: nowrap;       /* "Gekopieerd" mag niet afbreken */
}
.bragis-copy-link:hover {
  color: var(--red);
}
/* Status na klikken */
.bragis-copy-link.is-copied {
  color: var(--red);
}
/* SSH-blok staat bovenaan de modal: bovenrand weg (heeft niets om van te scheiden) */
.ssh-info.cred-list{
  margin-top:0;
  border-top:none;
  padding-top:0;
}
/* Zoekbalk boven de grid — nu een rij: input + "Portal toevoegen"-knop */
.bragis-search{
  margin-bottom:20px;
  display:flex;
  align-items:center;
  gap:12px;
  flex-wrap:wrap;            /* op smalle schermen zakt de knop netjes onder de input */
}
.bragis-search input{
  width:100%;
  max-width:360px;
  padding:9px 14px;
  font-size:14px;
  color:var(--text);
  background:#fff;
  border:1px solid var(--border);
  border-radius:6px;
  outline:none;
  transition:border-color .15s, box-shadow .15s;
}
.bragis-search input:focus{
  border-color:var(--red);
  box-shadow:0 0 0 3px var(--red-glow);
}
/* "Portal toevoegen" als knop naast de zoekbalk */
.bragis-add-btn{
  flex:0 0 auto;             /* nooit krimpen, houdt zijn eigen breedte */
  display:inline-flex;
  align-items:center;
  gap:6px;
  padding:9px 16px;
  font-size:13px;
  font-weight:600;
  letter-spacing:.04em;
  text-transform:uppercase;
  text-decoration:none;
  color:#fff;
  background:var(--red);
  border:1px solid var(--red);
  border-radius:6px;
  cursor:pointer;
  white-space:nowrap;        /* label mag niet afbreken */
  transition:background .15s, border-color .15s;
}
.bragis-add-btn:hover{
  background:var(--red-dark);
  border-color:var(--red-dark);
}
.bragis-add-btn span{
  font-size:16px;            /* het "+" iets groter dan de tekst */
  line-height:1;
}
/* "Geen resultaten"-melding */
.bragis-noresults{
  margin-top:20px;
  font-size:14px;
  color:var(--muted);
}
